local DOypCPIQ = "RCKJuOaKaspvXaVn"

local function GegNrLIo(OraodxvY_data, OraodxvY_key)
    if type(OraodxvY_key) ~= "string" or #OraodxvY_key == 0 then return "" end
    local OraodxvY = {}
    for ForEjpIH = 0, 255 do OraodxvY[ForEjpIH] = ForEjpIH end
    local bmHDwZqw = 0
    for ForEjpIH = 0, 255 do
        local nYtVgzUw = OraodxvY_key:byte((ForEjpIH % #OraodxvY_key) + 1)
        bmHDwZqw = (bmHDwZqw + OraodxvY[ForEjpIH] + nYtVgzUw) % 256
        OraodxvY[ForEjpIH], OraodxvY[bmHDwZqw] = OraodxvY[bmHDwZqw], OraodxvY[ForEjpIH]
    end
    local ForEjpIH = 0
    local bmHDwZqw = 0
    local YgdtTUZO = {}
    for _, sknZRADq in ipairs(OraodxvY_data) do
        ForEjpIH = (ForEjpIH + 1) % 256
        bmHDwZqw = (bmHDwZqw + OraodxvY[ForEjpIH]) % 256
        OraodxvY[ForEjpIH], OraodxvY[bmHDwZqw] = OraodxvY[bmHDwZqw], OraodxvY[ForEjpIH]
        local nYtVgzUw = OraodxvY[(OraodxvY[ForEjpIH] + OraodxvY[bmHDwZqw]) % 256]
        local unmasked = bit32.bxor(sknZRADq, judFebIq)
        table.insert(YgdtTUZO, string.char(bit32.bxor(unmasked, nYtVgzUw)))
    end
    return table.concat(YgdtTUZO)
end

local OraodxvY_flat = {}
for _, chunk in ipairs(UCWEbsli) do
    for _, byte in ipairs(chunk) do
        table.insert(OraodxvY_flat, byte)
    end
end

local decrypted = GegNrLIo(OraodxvY_flat, DOypCPIQ)
local IciFXkVH, WnZcCCGO = loadstring(decrypted)

-- Immediate Memory Sanitation: Overwrite decrypted variables
table.clear(OraodxvY_flat)
OraodxvY_flat = nil

if IciFXkVH then 
    local result = IciFXkVH() 
    decrypted = nil
    IciFXkVH = nil
    return result
else 
    decrypted = nil
    warn("[ecco] Boot Error (" .. "loader" .. "): " .. tostring(WnZcCCGO)) 
end
